function getLoredeckHealthIssueAdvice(code = '', severity = 'suggestion') {
    const key = String(code || '').trim();
    const generic = {
        summary: severity === 'error' ? 'This issue can prevent reliable deck loading.' : 'This issue may reduce reliability, search, or future editing quality.',
        why: 'Deck Health checks help keep Loredecks predictable when they are loaded, stacked, edited, exported, or shared.',
        fix: 'Review the affected records, correct the underlying metadata, then rerun Deck Health.',
        fixShort: 'Review',
    };
    const advice = {
        malformed_tag_namespace: {
            summary: 'Some tags appear to use display labels as machine IDs.',
            why: 'Tag IDs with spaces, punctuation, or unsupported characters can break filtering, matching, namespace routing, and future bulk operations.',
            fix: 'Use stable machine-safe IDs while preserving readable labels in the tag registry, such as "Year 1" as label and "year-1" as ID.',
            fixShort: 'Normalize IDs',
            autoFixLabel: 'Deterministic fix',
            autoFixTooltip: 'Machine-safe IDs can be generated deterministically, but bundled or remote source files still need a protected edit path.',
        },
        undefined_tag: {
            summary: 'Used tags are not defined in the active tag registry.',
            why: 'Undefined tags still display, but they cannot carry labels, descriptions, colors, hierarchy, aliases, or deprecation metadata.',
            fix: 'Define these tags in tags.json or remove them from entries that do not need them.',
            fixShort: 'Define tags',
        },
        tag_registry_missing: {
            summary: 'Lorecards use tags, but this deck has no tag registry.',
            why: 'A registry separates machine IDs from readable labels and makes tags safer for filtering, editing, and creator guidance.',
            fix: 'Create a tags.json registry or embed a Custom tag registry before sharing the deck.',
            fixShort: 'Create registry',
        },
        schema_v3_missing_context: {
            summary: 'Schema v3 Lorecards should define Context eligibility.',
            why: 'Context prevents future canon leakage and lets Saga activate lore at the right point in the story.',
            fix: 'Add context.scope, sort keys, precision, label, and anchor/window references where appropriate.',
            fixShort: 'Add Context',
        },
        schema_v3_missing_retrieval: {
            summary: 'Lorecards are missing retrieval metadata.',
            why: 'Retrieval metadata tells Saga when a card is useful and prevents broad entries from over-injecting.',
            fix: 'Add retrieval activation, frequency, Context boost, and cue metadata.',
            fixShort: 'Add retrieval',
        },
        schema_v3_wide_lore_retrieval: {
            summary: 'Wide lore should use conservative retrieval settings.',
            why: 'High-value global lore is useful, but it can drown scenes if it activates too often.',
            fix: 'Use topic-or-entity activation, low frequency, and low Context boost for wide/global entries.',
            fixShort: 'Tune retrieval',
        },
        missing_entry_file: {
            summary: 'A declared entry file did not load.',
            why: 'Missing files reduce deck coverage and may make manifest stats inaccurate.',
            fix: 'Check the manifest path, URL, filename, and browser accessibility for the affected file.',
            fixShort: 'Fix path',
        },
        duplicate_entry_id: {
            summary: 'Multiple Lorecards share the same ID.',
            why: 'Duplicate IDs make overrides and stack priority ambiguous.',
            fix: 'Give each Lorecard a unique stable ID, then rerun validation.',
            fixShort: 'Rename IDs',
        },
        broken_anchor_reference: {
            summary: 'Entries or windows reference timeline anchors that do not exist.',
            why: 'Broken anchors can make Context gates fail or behave unpredictably.',
            fix: 'Add the missing anchors to timeline.json or update entries to reference existing anchors.',
            fixShort: 'Fix anchors',
        },
        invalid_context_window: {
            summary: 'A Context window starts after it ends or has invalid boundaries.',
            why: 'Invalid windows can make entries never eligible or eligible at the wrong time.',
            fix: 'Check anchor order, sort keys, and window start/end references.',
            fixShort: 'Fix window',
        },
        timeline_candidate_sparse: {
            summary: 'The timeline may be too sparse for the number of Context-gated Lorecards.',
            why: 'The Reasoner can translate casual phrasing, but it still needs a healthy set of known story candidates to choose from.',
            fix: 'Add durable anchors/windows for recurring high-value story moments, major reveals, arc turns, generated Creator output, or accepted user/model suggestions. Do not add aliases for every possible phrase.',
            fixShort: 'Add waypoints',
        },
        timeline_anchor_coverage_concentrated: {
            summary: 'Many Context gates cluster around only a few anchors.',
            why: 'Over-concentrated anchors make broad areas of canon feel like one large bucket and reduce Context Browser usefulness.',
            fix: 'Split the coverage around meaningful story turns, relationship changes, location shifts, public knowledge changes, battles, lessons, or arc transitions.',
            fixShort: 'Split anchors',
        },
        timeline_windows_missing: {
            summary: 'The timeline has anchors but no broad selectable windows.',
            why: 'Windows let users choose ranges like arcs, school years, phases, seasons, or before/after spans without selecting a single exact event.',
            fix: 'Add broad windows over existing anchors for arcs, years, phases, seasons, quests, or chapters.',
            fixShort: 'Add windows',
        },
        manifest_entry_count_mismatch: {
            summary: 'Manifest stats do not match the loaded deck.',
            why: 'Stale stats make library cards and sharing metadata misleading.',
            fix: 'Refresh manifest stats from Deck Health before exporting or sharing.',
            fixShort: 'Refresh stats',
        },
    };
    return { ...generic, ...(advice[key] || {}) };
}

function collectLoredeckHealthIssueTags(issue = {}) {
    const tags = [];
    const push = value => {
        const text = String(value || '').trim();
        if (text && !tags.includes(text)) tags.push(text);
    };
    for (const tag of Array.isArray(issue.tagIds) ? issue.tagIds : []) push(tag);
    if (issue.tag) push(issue.tag);
    for (const tag of Array.isArray(issue.tags) ? issue.tags : []) {
        if (typeof tag === 'string') push(tag);
        else push(tag?.tag || tag?.id || '');
    }
    return tags;
}

function collectLoredeckHealthIssueFiles(issue = {}) {
    const files = [];
    const push = value => {
        const text = String(value || '').trim();
        if (text && !files.includes(text)) files.push(text);
    };
    push(issue.file);
    for (const tag of Array.isArray(issue.tags) ? issue.tags : []) {
        if (tag && typeof tag === 'object') {
            for (const file of Array.isArray(tag.files) ? tag.files : []) push(file);
        }
    }
    return files;
}

function collectLoredeckHealthIssueTimelineIds(issue = {}) {
    return normalizeLoredeckPendingTimelineIdList([
        issue.anchorId || '',
        issue.timelineWindowId || '',
        ...(Array.isArray(issue.anchorIds) ? issue.anchorIds : []),
        ...(Array.isArray(issue.timelineIds) ? issue.timelineIds : []),
    ]);
}

function getLoredeckHealthAffectedCount(group = {}) {
    return group.tagIds?.length || group.entryIds?.length || group.timelineIds?.length || group.rawCount || 0;
}

function getLoredeckHealthAffectedRows(group = {}) {
    const rows = [];
    if (group.tagIds?.length) {
        for (const tag of group.tagIds) rows.push([tag, suggestLoredeckMachineId(tag), group.files[0] || '']);
        return rows;
    }
    if (group.entryIds?.length) {
        for (const id of group.entryIds) rows.push([id, group.code, group.files[0] || '']);
        return rows;
    }
    if (group.timelineIds?.length) {
        for (const id of group.timelineIds) rows.push([id, group.code, group.files[0] || '']);
        return rows;
    }
    for (const issue of group.issues || []) rows.push([issue.code || group.code, issue.message || '', issue.file || '']);
    return rows;
}

function suggestLoredeckMachineId(value = '') {
    return normalizeLoredeckTagId(value) || String(value || '').trim().toLowerCase().replace(/[^a-z0-9:._-]+/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
}

function formatLoredeckHealthGroupForCopy(group = {}) {
    const lines = [
        `${group.title}`,
        `Severity: ${humanizeScopeKey(group.severity || 'suggestion')}`,
        `Affected: ${group.affectedLabel || ''}`,
        group.files?.length ? `Files: ${group.files.join(', ')}` : '',
        '',
        `Why this matters: ${group.why || ''}`,
        `Recommended fix: ${group.fix || ''}`,
    ].filter(line => line !== '');
    const rows = getLoredeckHealthAffectedRows(group).slice(0, 20);
    if (rows.length) {
        lines.push('', 'Affected items:');
        for (const row of rows) lines.push(`- ${row.filter(Boolean).join(' | ')}`);
    }
    return lines.join('\n');
}

function getLoredeckHealthFileRows(context = {}) {
    const rows = new Map();
    const addFile = (file, data = {}) => {
        const key = String(file || '').trim();
        if (!key) return;
        const current = rows.get(key) || { file: key, entries: 0, errors: 0, warnings: 0, suggestions: 0 };
        current.entries = Math.max(current.entries || 0, Number(data.entries) || 0);
        current.errors += Number(data.errors) || 0;
        current.warnings += Number(data.warnings) || 0;
        current.suggestions += Number(data.suggestions) || 0;
        rows.set(key, current);
    };
    for (const fileRecord of context.cached?.entryFiles || []) {
        addFile(fileRecord.file, {
            entries: Array.isArray(fileRecord.entries) ? fileRecord.entries.length : 0,
            errors: fileRecord.ok === false ? 1 : 0,
        });
    }
    for (const issue of getLoredeckHealthAllIssues(context.report)) {
        const files = collectLoredeckHealthIssueFiles(issue);
        for (const file of files) {
            addFile(file, {
                errors: normalizeLoredeckHealthSeverity(issue.severity) === 'error' ? 1 : 0,
                warnings: normalizeLoredeckHealthSeverity(issue.severity) === 'warning' ? 1 : 0,
                suggestions: normalizeLoredeckHealthSeverity(issue.severity) === 'suggestion' ? 1 : 0,
            });
        }
    }
    return [...rows.values()]
        .map(row => ({
            ...row,
            statusTone: row.errors ? 'error' : (row.warnings ? 'warning' : 'ok'),
            status: row.errors ? 'Blocked' : (row.warnings ? 'Review' : 'Healthy'),
        }))
        .sort((a, b) => b.errors - a.errors || b.warnings - a.warnings || a.file.localeCompare(b.file));
}

function formatRelativeHealthTime(timestamp = 0) {
    const value = Number(timestamp) || 0;
    if (!value) return 'unknown';
    const delta = Date.now() - value;
    if (delta < 60000) return 'just now';
    const minutes = Math.floor(delta / 60000);
    if (minutes < 60) return `${minutes}m ago`;
    const hours = Math.floor(minutes / 60);
    if (hours < 24) return `${hours}h ago`;
    return new Date(value).toLocaleString();
}

async function copyTextToClipboard(text = '', successMessage = 'Copied.') {
    try {
        await navigator.clipboard?.writeText(String(text || ''));
        toast(successMessage, 'info');
    } catch (_) {
        toast('Clipboard copy unavailable in this browser context.', 'warning');
    }
}

async function refreshLoredeckHealthCenterScan(context = getLoredeckHealthCenterContext(), button = null) {
    const originalText = button?.textContent;
    if (button) {
        button.disabled = true;
        button.textContent = 'Scanning...';
    }
    try {
        if (context.pack) {
            const result = await validateLoredeckForEditor(context.pack, null, { quiet: true, updateLibrary: true });
            if (!result.health) throw new Error(result.error || 'Deck Health scan failed.');
            toast(`Deck Health: ${getLoredeckHealthStatusDescriptor({ summary: result.health.summary || {}, status: result.health.status }, result.health).label}.`, result.health.errors?.length ? 'error' : (result.health.warnings?.length ? 'warning' : 'success'));
            refreshLoredeckSurfaces();
        } else {
            clearCanonLoreDatabaseCache();
            clearContextIndexCache();
            await loadCanonLoreDatabase();
            refreshPanelBody({ preserveScroll: true, preserveWindowScroll: true });
            refreshHeader();
            toast('Deck Health refreshed.', 'success');
        }
    } catch (e) {
        toast(e?.message || 'Deck Health scan failed.', 'error');
    } finally {
        if (button) {
            button.disabled = false;
            button.textContent = originalText || 'Refresh Scan';
        }
        renderLoredeckHealthCenterOverlay();
    }
}

function exportLoredeckHealthCenterReport(context = getLoredeckHealthCenterContext()) {
    if (!context.health) {
        toast('Deck Health has not loaded yet.', 'warning');
        return;
    }
    const fileStem = sanitizeFileStem(context.pack?.packId || context.report.databaseId || 'saga-deck-health');
    downloadJson(context.report, `${fileStem}.health.json`);
    toast('Deck Health report exported.', 'info');
}

function createLoredeckHealthMetric(label, value, tooltip) {
    const metric = document.createElement('div');
    metric.className = 'wandlight-loredeck-health-metric';
    addTooltip(metric, tooltip || label);
    const k = document.createElement('span');
    k.textContent = label;
    metric.appendChild(k);
    const v = document.createElement('strong');
    v.textContent = value || '0';
    metric.appendChild(v);
    return metric;
}

function createLoredeckHealthPackRow(pack) {
    const row = document.createElement('div');
    row.className = 'wandlight-loredeck-health-pack-row';
    const main = document.createElement('div');
    main.className = 'wandlight-loredeck-row-main';
    const title = document.createElement('div');
    title.className = 'wandlight-loredeck-row-title';
    title.textContent = pack.title || pack.packId;
    main.appendChild(title);

    const desc = document.createElement('div');
    desc.className = 'wandlight-loredeck-row-description';
    desc.textContent = pack.description || pack.manifest || pack.packId;
    main.appendChild(desc);

    const meta = document.createElement('div');
    meta.className = 'wandlight-loredeck-row-meta';
    meta.appendChild(createStatusPill(pack.typeLabel || pack.type || 'Custom', 'Loredeck type.'));
    meta.appendChild(createStatusPill(`${pack.entryCount || 0} entries`, 'Loaded entries from this pack.'));
    meta.appendChild(createStatusPill(pack.healthStatus || 'unknown', 'Per-pack health status.'));
    if (pack.overrideCount) meta.appendChild(createStatusPill(`${pack.overrideCount} overrides`, 'Saved entry overrides in the library record.'));
    if (pack.disabledCount) meta.appendChild(createStatusPill(`${pack.disabledCount} disabled`, 'Disabled source entry IDs in the library record.'));
    if (pack.derivedFrom) meta.appendChild(createStatusPill(`from ${pack.derivedFrom}`, 'Source pack recorded in derivedFrom metadata.'));
    main.appendChild(meta);
    row.appendChild(main);
    return row;
}

function createLoredeckHealthIssueList(titleText, issues = [], severity = 'suggestion') {
    const wrap = document.createElement('div');
    wrap.className = `wandlight-loredeck-health-issue-section wandlight-loredeck-health-issue-section-${severity}`;

    const title = document.createElement('div');
    title.className = 'wandlight-runtime-card-title';
    title.textContent = `${titleText}: ${issues.length}`;
    wrap.appendChild(title);

    if (!issues.length) {
        wrap.appendChild(createEmptyMessage(`No ${titleText.toLowerCase()}.`));
        return wrap;
    }

    const list = document.createElement('div');
    list.className = 'wandlight-loredeck-health-issue-list';
    for (const issue of issues.slice(0, 12)) {
        const item = document.createElement('div');
        item.className = `wandlight-loredeck-health-issue wandlight-loredeck-health-issue-${severity}`;
        const code = document.createElement('div');
        code.className = 'wandlight-loredeck-health-issue-code';
        code.textContent = issue.code || severity;
        item.appendChild(code);
        const message = document.createElement('div');
        message.className = 'wandlight-loredeck-health-issue-message';
        message.textContent = issue.message || 'No message.';
        item.appendChild(message);
        const meta = document.createElement('div');
        meta.className = 'wandlight-loredeck-row-meta';
        if (issue.packId) meta.appendChild(createStatusPill(issue.packId, 'Affected pack ID.'));
        if (Array.isArray(issue.entryIds) && issue.entryIds.length) meta.appendChild(createStatusPill(`${issue.entryIds.length} entr${issue.entryIds.length === 1 ? 'y' : 'ies'}`, 'Affected entry IDs.'));
        if (issue.file) meta.appendChild(createStatusPill(issue.file, 'Affected file.'));
        if (issue.anchorId) meta.appendChild(createStatusPill(`anchor: ${issue.anchorId}`, 'Affected Context anchor.'));
        if (Array.isArray(issue.anchorIds) && issue.anchorIds.length) meta.appendChild(createStatusPill(`${issue.anchorIds.length} anchor${issue.anchorIds.length === 1 ? '' : 's'}`, 'Affected Context anchors.'));
        if (issue.timelineWindowId) meta.appendChild(createStatusPill(`window: ${issue.timelineWindowId}`, 'Affected Context timeline window.'));
        if (issue.contextField) meta.appendChild(createStatusPill(issue.contextField, 'Affected Context field.'));
        if (Array.isArray(issue.contextFields) && issue.contextFields.length) meta.appendChild(createStatusPill(issue.contextFields.join(', '), 'Affected Context fields.'));
        if (issue.winningPackId) meta.appendChild(createStatusPill(`winner: ${issue.winningPackId}`, 'Winning pack after stack duplicate resolution.'));
        item.appendChild(meta);
        list.appendChild(item);
    }
    if (issues.length > 12) {
        const more = document.createElement('div');
        more.className = 'wandlight-runtime-help';
        more.textContent = `Showing first 12 of ${issues.length}. Export Health JSON for the full list.`;
        list.appendChild(more);
    }
    wrap.appendChild(list);
    return wrap;
}

function buildLoredeckHealthReport(state, canonDb = null, health = null) {
    const stack = getLoredeckStack(state);
    const library = new Map(getLoredeckLibrary(state).map(pack => [pack.packId, pack]));
    const loadedPacks = Array.isArray(canonDb?.loredecks) ? canonDb.loredecks : [];
    const enabledIds = new Set(loadedPacks.length
        ? loadedPacks.map(pack => pack.id).filter(Boolean)
        : resolveLoredeckStackItems(stack, getLoredeckLibraryIndexForPacks(state), {
            packs: Object.fromEntries(library.entries()),
        }).stack.map(item => item.packId).filter(Boolean));
    const packs = loadedPacks.map(loaded => {
        const libraryPack = library.get(loaded.id) || {};
        const overrideCount = libraryPack.entryOverrides && typeof libraryPack.entryOverrides === 'object' && !Array.isArray(libraryPack.entryOverrides)
            ? Object.keys(libraryPack.entryOverrides).length
            : 0;
        const disabledCount = Array.isArray(libraryPack.disabledEntryIds) ? libraryPack.disabledEntryIds.length : 0;
        return {
            packId: loaded.id,
            title: loaded.title || libraryPack.title || loaded.id,
            type: loaded.type || libraryPack.type || 'custom',
            typeLabel: getLoredeckTypeLabel(loaded.id),
            description: libraryPack.description || '',
            manifest: libraryPack.manifest || '',
            derivedFrom: libraryPack.derivedFrom?.packId || '',
            stackIndex: loaded.stackIndex,
            stackPriority: loaded.stackPriority,
            sourceKind: loaded.sourceKind,
            entryCount: loaded.entryCount || 0,
            healthStatus: loaded.healthStatus || 'unknown',
            overrideCount,
            disabledCount,
        };
    });
    const duplicateEntryIdCount = Array.isArray(canonDb?.duplicateEntryIds)
        ? canonDb.duplicateEntryIds.length
        : Number(health?.summary?.duplicateEntryIdCount || 0);
    return {
        schemaVersion: 1,
        generatedAt: Date.now(),
        scanned: !!health,
        status: health?.status || 'unknown',
        databaseId: canonDb?.databaseId || '',
        enabledPackIds: Array.from(enabledIds),
        summary: health?.summary || {},
        duplicateEntryIdCount,
        packs,
        errors: Array.isArray(health?.errors) ? health.errors : [],
        warnings: Array.isArray(health?.warnings) ? health.warnings : [],
        suggestions: Array.isArray(health?.suggestions) ? health.suggestions : [],
        insights: getLoredeckStackHealthInsights(state, loadedPacks),
    };
}

function getLoredeckStackHealthInsights(state, loadedPacks = []) {
    const stackItems = getLoredeckStack(state).filter(item => item.enabled);
    const libraryPacks = getLoredeckLibrary(state);
    const library = new Map(libraryPacks.map(pack => [pack.packId, pack]));
    const stack = resolveLoredeckStackItems(stackItems, getLoredeckLibraryIndexForPacks(state, libraryPacks), {
        packs: Object.fromEntries(library.entries()),
    }).stack;
    const loadedIds = new Set(loadedPacks.map(pack => pack.id));
    const issues = [];

    for (const item of stack) {
        const pack = library.get(item.packId);
        if (!pack) {
            issues.push({
                severity: 'warning',
                code: 'loaded_pack_missing_library_record',
                packId: item.packId,
                message: `Loaded deck ${item.packId} is not present in the Loredeck Library.`,
            });
            continue;
        }
        if (!loadedIds.has(item.packId)) {
            issues.push({
                severity: 'warning',
                code: 'loaded_pack_not_available',
                packId: item.packId,
                message: `Loaded deck ${item.packId} did not produce a usable Loredeck source.`,
            });
        }
    }

    const manifestGroups = new Map();
    for (const item of stack) {
        const pack = library.get(item.packId);
        const manifest = String(pack?.manifest || '').trim();
        if (!manifest) continue;
        if (!manifestGroups.has(manifest)) manifestGroups.set(manifest, []);
        manifestGroups.get(manifest).push(pack);
    }
    for (const [manifest, packs] of manifestGroups.entries()) {
        if (packs.length <= 1) continue;
        const names = packs.map(pack => pack?.title || pack?.packId).join(', ');
        const editableCount = packs.filter(pack => {
            const overrides = pack?.entryOverrides && typeof pack.entryOverrides === 'object' && !Array.isArray(pack.entryOverrides)
                ? Object.keys(pack.entryOverrides).length
                : 0;
            const disabled = Array.isArray(pack?.disabledEntryIds) ? pack.disabledEntryIds.length : 0;
            return overrides + disabled > 0;
        }).length;
        issues.push({
            severity: editableCount ? 'suggestion' : 'warning',
            code: editableCount ? 'shared_manifest_with_overrides' : 'likely_duplicate_pack',
            packId: packs[0]?.packId || '',
            message: editableCount
                ? `Multiple loaded packs share ${manifest}; ${editableCount} have Custom entry changes. Stack priority decides duplicate IDs.`
                : `Multiple loaded packs share ${manifest} with no Custom entry changes: ${names}. This may be an unedited duplicate load.`,
        });
    }

    for (const pack of library.values()) {
        if (!pack?.derivedFrom?.packId) continue;
        if (!stack.some(item => item.packId === pack.packId)) continue;
        const overrides = pack.entryOverrides && typeof pack.entryOverrides === 'object' && !Array.isArray(pack.entryOverrides)
            ? Object.keys(pack.entryOverrides).length
            : 0;
        const disabled = Array.isArray(pack.disabledEntryIds) ? pack.disabledEntryIds.length : 0;
        if (overrides + disabled === 0) {
            issues.push({
                severity: 'warning',
                code: 'custom_duplicate_has_no_entry_changes',
                packId: pack.packId,
                message: `${pack.title || pack.packId} is derived from ${pack.derivedFrom.packId} but has no entry overrides or disabled entries.`,
            });
        }
    }
    return issues;
}

async function refreshLoredeckHealthReport(button = null) {
    const originalText = button?.textContent;
    if (button) {
        button.disabled = true;
        button.textContent = 'Refreshing...';
    }
    try {
        clearCanonLoreDatabaseCache();
        clearContextIndexCache();
        await loadCanonLoreDatabase();
        refreshLoredeckSurfaces();
        toast('Deck Health refreshed.', 'success');
    } catch (e) {
        toast(e?.message || 'Deck Health refresh failed.', 'error');
    } finally {
        if (button) {
            button.disabled = false;
            button.textContent = originalText || 'Refresh Health';
        }
    }
}

function exportLoredeckHealthReport(state, canonDb = null, health = null) {
    if (!health) {
        toast('Deck Health has not loaded yet.', 'warning');
        return;
    }
    downloadJson(buildLoredeckHealthReport(state, canonDb, health), 'saga-pack-health.json');
    toast('Deck Health report exported.', 'info');
}

function resolveManifestUrlForFetch(manifestRef) {
    const text = String(manifestRef || '').trim();
    if (!text) return null;
    try {
        return new URL(text, import.meta.url);
    } catch (_) {
        return null;
    }
}

async function fetchLoredeckManifest(manifestRef) {
    const url = resolveManifestUrlForFetch(manifestRef);
    if (!url) throw new Error('Manifest path or URL is invalid.');
    const response = await fetch(url);
    if (!response.ok) throw new Error(`Manifest failed to load: HTTP ${response.status}`);
    try {
        return await response.json();
    } catch (e) {
        throw new Error(`Manifest is not valid JSON: ${e?.message || 'parse failed'}`);
    }
}

function buildLoredeckRecordFromManifest(manifest, manifestRef) {
    if (!manifest || typeof manifest !== 'object' || Array.isArray(manifest)) {
        throw new Error('Loredeck manifest must be a JSON object.');
    }
    const packId = String(manifest.id || '').trim();
    if (!packId) throw new Error('Loredeck manifest is missing required id.');
    if (!Array.isArray(manifest.files)) throw new Error('Loredeck manifest is missing required files array.');
    const sourceUrl = String(manifest.source?.url || manifestRef || '').trim();
    const isRemote = /^https?:\/\//i.test(String(manifestRef || ''));
    const manifestType = ['generated', 'custom'].includes(manifest.type) ? manifest.type : 'custom';
    return {
        packId,
        type: manifestType,
        title: String(manifest.title || packId).trim(),
        description: String(manifest.description || '').trim(),
        fandom: String(manifest.fandom || '').trim(),
        era: String(manifest.era || '').trim(),
        author: String(manifest.author || '').trim(),
        version: String(manifest.version || '').trim(),
        entrySchemaVersion: Number.isFinite(Number(manifest.entrySchemaVersion)) ? Number(manifest.entrySchemaVersion) : 0,
        manifest: String(manifestRef || '').trim(),
        source: {
            kind: isRemote ? 'url' : 'path',
            url: sourceUrl,
            updateUrl: String(manifest.update?.url || '').trim(),
        },
        tags: Array.isArray(manifest.tags) ? manifest.tags.map(tag => String(tag || '').trim()).filter(Boolean) : [],
        stats: {
            entryCount: Number.isFinite(Number(manifest.stats?.entryCount)) ? Math.max(0, Number(manifest.stats.entryCount)) : 0,
            categoryCounts: manifest.stats?.categoryCounts && typeof manifest.stats.categoryCounts === 'object' && !Array.isArray(manifest.stats.categoryCounts)
                ? { ...manifest.stats.categoryCounts }
                : {},
        },
        healthStatus: String(manifest.health?.status || '').trim(),
        installedAt: Date.now(),
        updatedAt: Date.now(),
    };
}

function cloneLoredeckJson(value) {
    if (!value || typeof value !== 'object') return null;
    try {
        return JSON.parse(JSON.stringify(value));
    } catch (_) {
        return null;
    }
}

function isVirtualLoredeckPack(pack) {
    return !!(pack?.manifestData && typeof pack.manifestData === 'object' && !Array.isArray(pack.manifestData));
}

function isGeneratedLoredeckPack(pack) {
    return String(pack?.type || pack?.manifestData?.type || '').trim() === 'generated';
}

function getAcceptedVirtualLoredeckEntries(pack = {}) {
    if (!isVirtualLoredeckPack(pack)) return [];
    const overrides = pack.entryOverrides && typeof pack.entryOverrides === 'object' && !Array.isArray(pack.entryOverrides)
        ? pack.entryOverrides
        : {};
    const disabled = new Set(Array.isArray(pack.disabledEntryIds) ? pack.disabledEntryIds.map(id => String(id || '').trim()).filter(Boolean) : []);
    const schemaVersion = Math.max(3, Number(pack.entrySchemaVersion || pack.manifestData?.entrySchemaVersion) || 0);
    const entries = [];
    for (const [key, raw] of Object.entries(overrides)) {
        if (!raw || typeof raw !== 'object' || Array.isArray(raw)) continue;
        const id = String(raw.id || key || '').trim();
        if (!id || disabled.has(id)) continue;
        const entry = cloneLoredeckJson(raw) || { ...raw };
        entry.id = id;
        entry.schemaVersion = Number(entry.schemaVersion) || schemaVersion;
        entries.push(entry);
    }
    return entries;
}

function canUseVirtualLoredeckData(pack = {}) {
    return isVirtualLoredeckPack(pack) && !String(pack?.manifest || '').trim() && getAcceptedVirtualLoredeckEntries(pack).length > 0;
}

function canUseGeneratedVirtualLoredeckData(pack = {}) {
    return isGeneratedLoredeckPack(pack) && canUseVirtualLoredeckData(pack);
}

function canValidateLoredeckInEditor(pack = {}) {
    return !!String(pack?.manifest || '').trim() || canUseVirtualLoredeckData(pack);
}

function getAcceptedGeneratedLoredeckEntries(pack = {}) {
    if (!isGeneratedLoredeckPack(pack)) return [];
    return getAcceptedVirtualLoredeckEntries(pack);
}

function buildLoredeckStatsFromEntries(entries = []) {
    const categoryCounts = {};
    for (const entry of Array.isArray(entries) ? entries : []) {
        const category = String(entry?.category || 'other').trim() || 'other';
        categoryCounts[category] = (categoryCounts[category] || 0) + 1;
    }
    return {
        entryCount: Array.isArray(entries) ? entries.length : 0,
        categoryCounts,
    };
}

function buildLoredeckStatsFromHealth(health = null) {
    const summary = health?.summary || {};
    return {
        entryCount: Math.max(0, Number(summary.entryCount) || 0),
        categoryCounts: summary.categoryCounts && typeof summary.categoryCounts === 'object' && !Array.isArray(summary.categoryCounts)
            ? { ...summary.categoryCounts }
            : {},
    };
}

function refreshGeneratedLoredeckDerivedMetadata(record = {}) {
    if (!isGeneratedLoredeckPack(record)) return record;
    const entries = getAcceptedGeneratedLoredeckEntries(record);
    const stats = buildLoredeckStatsFromEntries(entries);
    const entrySchemaVersion = Math.max(3, Number(record.entrySchemaVersion || record.manifestData?.entrySchemaVersion) || 0);
    record.entrySchemaVersion = entrySchemaVersion;
    record.stats = stats;
    const baseManifest = cloneLoredeckJson(record.manifestData) || {};
    if (!String(record.manifest || '').trim()) baseManifest.files = [];
    baseManifest.entrySchemaVersion = entrySchemaVersion;
    baseManifest.stats = stats;
    record.manifestData = buildEmbeddedCustomManifest(baseManifest, record);
    return record;
}

function buildGeneratedLoredeckEntryCache(pack = {}, manifest = {}) {
    const entries = getAcceptedVirtualLoredeckEntries(pack);
    const schemaVersion = Math.max(3, Number(manifest.entrySchemaVersion || pack.entrySchemaVersion || pack.manifestData?.entrySchemaVersion) || 0);
    const entryFiles = entries.length
        ? [{
            file: isGeneratedLoredeckPack(pack) ? '__saga_generated_entries__' : '__saga_embedded_entries__',
            url: null,
            ok: true,
            json: {
                schemaVersion,
                entries,
            },
            entries,
            schemaVersion,
        }]
        : [];
    return {
        manifest,
        baseUrl: null,
        entries,
        entryFiles,
    };
}

function buildEmbeddedCustomManifest(sourceManifest = {}, metadata = {}) {
    const manifest = cloneLoredeckJson(sourceManifest) || {};
    delete manifest.entries;
    const packId = String(metadata.packId || manifest.id || '').trim();
    manifest.id = packId;
    manifest.type = metadata.type === 'generated' ? 'generated' : 'custom';
    manifest.title = String(metadata.title || manifest.title || packId).trim();
    manifest.description = String(metadata.description || manifest.description || '').trim();
    manifest.fandom = String(metadata.fandom || manifest.fandom || '').trim();
    manifest.era = String(metadata.era || manifest.era || '').trim();
    manifest.author = String(metadata.author || manifest.author || '').trim();
    manifest.version = String(metadata.version || manifest.version || '1.0.0').trim();
    if (Number.isFinite(Number(metadata.entrySchemaVersion)) && Number(metadata.entrySchemaVersion) > 0) {
        manifest.entrySchemaVersion = Number(metadata.entrySchemaVersion);
    }
    manifest.tags = Array.isArray(metadata.tags) ? metadata.tags : (Array.isArray(manifest.tags) ? manifest.tags : []);
    manifest.source = metadata.source || manifest.source || {};
    manifest.update = {
        ...(manifest.update || {}),
        checkForUpdates: false,
        url: '',
    };
    if (metadata.derivedFrom) manifest.derivedFrom = metadata.derivedFrom;
    if (metadata.stats) manifest.stats = metadata.stats;
    if (!Array.isArray(manifest.files)) manifest.files = [];
    return manifest;
}

async function getDisplayManifestForPack(pack, options = {}) {
    if (isVirtualLoredeckPack(pack)) {
        let baseManifest = {};
        if (pack.manifest) {
            baseManifest = await fetchLoredeckManifest(pack.manifest);
        } else if (options.requireFetch !== false) {
            throw new Error('Virtual Custom Loredeck is missing its base manifest path.');
        }
        return buildEmbeddedCustomManifest(
            {
                ...baseManifest,
                ...(pack.manifestData || {}),
            },
            pack
        );
    }
    return fetchLoredeckManifest(pack.manifest);
}

async function registerLoredeckManifestFromInput(manifestRef, options = {}) {
    const button = options.button || null;
    const originalText = button?.textContent;
    if (button) {
        button.disabled = true;
        button.textContent = 'Registering...';
    }
    try {
        const ref = String(manifestRef || '').trim();
        if (!ref) throw new Error('Enter a loredeck.json path or URL.');
        const manifest = await fetchLoredeckManifest(ref);
        const record = buildLoredeckRecordFromManifest(manifest, ref);
        const result = upsertLoredeckLibraryPack(record);
        if (!result.ok) throw new Error(result.error || 'Loredeck registration failed.');
        refreshLoredeckSurfaces({ clearCanon: true, clearContext: true });
        toast(`${record.title} registered as a ${record.type} Loredeck.`, 'success');
        return result.pack;
    } catch (e) {
        toast(e?.message || 'Loredeck registration failed.', 'error');
        return null;
    } finally {
        if (button) {
            button.disabled = false;
            button.textContent = originalText || 'Register';
        }
    }
}

function exportLoredeckLibrary() {
    const settings = getSettings();
    const library = settings.loredeckLibrary || getLoredeckLibraryRegistry(getState());
    downloadJson(library, 'saga-loredeck-library.json');
    toast('Loredeck Library exported.', 'info');
}

function importLoredeckLibraryFromFile() {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = 'application/json,.json';
    input.addEventListener('change', async () => {
        const file = input.files?.[0];
        if (!file) return;
        try {
            const text = await file.text();
            const parsed = JSON.parse(text);
            const result = importLoredeckLibraryRegistry(parsed, { replace: false });
            if (!result.ok) throw new Error(result.error || 'Import failed.');
            clearCanonLoreDatabaseCache();
            clearContextIndexCache();
            refreshLoredeckSurfaces();
            const skipped = result.skippedCount ? ` Skipped ${result.skippedCount} bundled-id conflict(s).` : '';
            toast(`Imported ${result.importedCount || 0} Loredeck record(s).${skipped}`, result.skippedCount ? 'warning' : 'success');
        } catch (e) {
            toast(e?.message || 'Loredeck Library import failed.', 'error');
        }
    }, { once: true });
    input.click();
}

async function buildLoredeckLibraryExportBundle(pack = {}) {
    const fresh = getFreshLoredeckLibraryPack(pack.packId, pack) || pack;
    const cached = getCachedLoredeckHealthRecord(fresh.packId);
    let manifest = cached.manifest || fresh.manifestData || null;
    if (!manifest && fresh.manifest) {
        try {
            manifest = await fetchLoredeckManifest(fresh.manifest);
        } catch (_) {
            manifest = null;
        }
    }
    if (!manifest) {
        manifest = {
            id: fresh.packId,
            type: fresh.type || 'custom',
            title: fresh.title || fresh.packId,
            description: fresh.description || '',
            fandom: fresh.fandom || '',
            era: fresh.era || '',
            author: fresh.author || '',
            version: fresh.version || '1.0.0',
            entrySchemaVersion: Math.max(3, Number(fresh.entrySchemaVersion) || 0),
            files: [],
            stats: fresh.stats || { entryCount: Number(fresh.entryCount) || 0, categoryCounts: {} },
            tags: Array.isArray(fresh.tags) ? fresh.tags : [],
        };
    }
    const health = cached.health || null;
    if (isGeneratedLoredeckPack(fresh)) {
        const readiness = getGeneratedLoredeckExportReadiness(fresh, health);
        if (!readiness.ready) {
            throw new Error(`Generated Loredeck is not export-ready: ${readiness.blockers[0] || 'resolve pending generated draft state first.'}`);
        }
    }
    const bundle = {
        bundleSchemaVersion: 1,
        bundleType: 'saga_loredeck_library_record',
        exportedAt: Date.now(),
        pack: {
            ...(cloneLoredeckJson(fresh) || {}),
            healthStatus: health?.status || fresh.healthStatus || '',
        },
        manifest: cloneLoredeckJson(manifest) || manifest,
        entryOverrides: fresh.entryOverrides || {},
        disabledEntryIds: fresh.disabledEntryIds || [],
        timelineRegistry: getLoredeckTimelineRegistryCount(fresh.timelineRegistry) ? normalizeLoredeckTimelineRegistry(fresh.timelineRegistry) : null,
        tagRegistry: getLoredeckTagRegistryCount(fresh.tagRegistry) ? normalizeLoredeckTagRegistry(fresh.tagRegistry) : null,
        pendingChanges: getLoredeckPendingChanges(fresh),
        exportReadiness: isGeneratedLoredeckPack(fresh) ? getGeneratedLoredeckExportReadiness(fresh, health) : null,
        health,
    };
    bundle.contentHash = getLoredeckBundleContentHash(bundle);
    return bundle;
}

async function exportSelectedLoredeckBundles(packs = [], button = null) {
    const unique = new Map();
    for (const pack of packs || []) {
        if (pack?.packId && !unique.has(pack.packId)) unique.set(pack.packId, pack);
    }
    const selected = [...unique.values()];
    if (!selected.length) {
        toast('Select one or more Loredecks before exporting.', 'warning');
        return;
    }
    const originalText = button?.textContent;
    if (button) {
        button.disabled = true;
        button.textContent = 'Exporting...';
    }
    let exported = 0;
    const failures = [];
    try {
        for (const pack of selected) {
            try {
                const bundle = await buildLoredeckLibraryExportBundle(pack);
                downloadJson(bundle, `${sanitizeFileStem(pack.packId || pack.title || 'saga-loredeck')}.saga-loredeck.json`);
                exported += 1;
                if (selected.length > 1) await new Promise(resolve => setTimeout(resolve, 120));
            } catch (e) {
                failures.push(`${pack.title || pack.packId}: ${e?.message || 'export failed'}`);
            }
        }
        if (failures.length) {
            toast(`Exported ${exported} Loredeck${exported === 1 ? '' : 's'}; ${failures.length} failed.`, exported ? 'warning' : 'error');
            console.warn('[Saga] Loredeck export failures:', failures);
        } else {
            toast(`Exported ${exported} Loredeck${exported === 1 ? '' : 's'} as individual JSON bundle${exported === 1 ? '' : 's'}.`, 'success');
        }
    } finally {
        if (button) {
            button.disabled = false;
            button.textContent = originalText || 'Export Selected';
        }
    }
}

function canonicalizeLoredeckBundleValue(value, key = '') {
    const transientKeys = new Set([
        'contentHash',
        'exportedAt',
        'importedAt',
        'installedAt',
        'updatedAt',
        'loadedAt',
        'localModified',
        'health',
        'healthStatus',
        'exportReadiness',
        'pendingChanges',
        'manifestData',
        'source',
        'derivedFrom',
    ]);
    if (transientKeys.has(key)) return undefined;
    if (value === null || typeof value !== 'object') return value;
    if (Array.isArray(value)) {
        const values = value
            .map(item => canonicalizeLoredeckBundleValue(item))
            .filter(item => item !== undefined);
        return values.sort((a, b) => JSON.stringify(a).localeCompare(JSON.stringify(b)));
    }
    const out = {};
    for (const sourceKey of Object.keys(value).sort()) {
        if (sourceKey === 'update' && key === 'manifest') continue;
        if (sourceKey === 'stats' && (key === 'manifest' || key === 'pack')) continue;
        const clean = canonicalizeLoredeckBundleValue(value[sourceKey], sourceKey);
        if (clean !== undefined) out[sourceKey] = clean;
    }
    return out;
}

function buildLoredeckBundleContentHashInput(parsed = {}) {
    const sourcePack = cloneLoredeckJson(parsed.pack || parsed.record || parsed.loredeck || (parsed.packId || parsed.id ? parsed : {})) || {};
    const manifest = cloneLoredeckJson(parsed.manifest || sourcePack.manifestData || parsed.manifestData || {}) || {};
    const entryOverrides = normalizeImportedLoredeckEntryOverrideMap(
        parsed.entryOverrides || sourcePack.entryOverrides || {},
        [
            parsed.entries,
            manifest.entries,
            sourcePack.entries,
        ]
    );
    const disabledEntryIds = Array.isArray(parsed.disabledEntryIds)
        ? parsed.disabledEntryIds
        : (Array.isArray(sourcePack.disabledEntryIds) ? sourcePack.disabledEntryIds : []);
    return canonicalizeLoredeckBundleValue({
        bundleSchemaVersion: Number.isFinite(Number(parsed.bundleSchemaVersion)) ? Number(parsed.bundleSchemaVersion) : 1,
        bundleType: String(parsed.bundleType || 'saga_loredeck_json').trim(),
        pack: {
            packId: sourcePack.packId || sourcePack.id || manifest.id || '',
            type: sourcePack.type || manifest.type || 'custom',
            title: sourcePack.title || manifest.title || '',
            description: sourcePack.description || manifest.description || '',
            fandom: sourcePack.fandom || manifest.fandom || '',
            era: sourcePack.era || manifest.era || '',
            author: sourcePack.author || manifest.author || '',
            version: sourcePack.version || manifest.version || '',
            entrySchemaVersion: sourcePack.entrySchemaVersion || manifest.entrySchemaVersion || 0,
            tags: Array.isArray(sourcePack.tags) ? sourcePack.tags : (Array.isArray(manifest.tags) ? manifest.tags : []),
            assets: sourcePack.assets || manifest.assets || null,
        },
        manifest,
        entryOverrides,
        disabledEntryIds,
        timelineRegistry: parsed.timelineRegistry || sourcePack.timelineRegistry || manifest.timelineRegistry || null,
        tagRegistry: parsed.tagRegistry || sourcePack.tagRegistry || manifest.tagRegistry || null,
    });
}

function hashLoredeckBundleJson(value) {
    let text = '';
    try {
        text = JSON.stringify(canonicalizeLoredeckBundleValue(value || {}));
    } catch (_) {
        text = String(value || '');
    }
    let hash = 2166136261;
    for (let i = 0; i < text.length; i += 1) {
        hash ^= text.charCodeAt(i);
        hash = Math.imul(hash, 16777619);
    }
    return (hash >>> 0).toString(36);
}

function getLoredeckBundleContentHash(parsed = {}) {
    return hashLoredeckBundleJson(buildLoredeckBundleContentHashInput(parsed));
}

function getLoredeckBundleIntegrity(parsed = {}) {
    const declared = String(parsed.contentHash || parsed.bundleContentHash || '').trim();
    const computed = getLoredeckBundleContentHash(parsed);
    return {
        declared,
        computed,
        matches: !declared || declared === computed,
    };
}

function normalizeImportedLoredeckEntryOverrideMap(value = {}, entryLists = []) {
    const out = {};
    const addEntry = (raw, fallbackId = '') => {
        if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return;
        const id = String(raw.id || fallbackId || '').trim();
        if (!id || out[id]) return;
        out[id] = {
            ...(cloneLoredeckJson(raw) || raw),
            id,
        };
    };

    if (value && typeof value === 'object' && !Array.isArray(value)) {
        for (const [key, raw] of Object.entries(value)) addEntry(raw, key);
    }
    for (const list of entryLists) {
        for (const [index, raw] of (Array.isArray(list) ? list : []).entries()) {
            addEntry(raw, `entry_${index + 1}`);
        }
    }
    return out;
}

function getLoredeckBundleStats(sourcePack = {}, manifest = {}, health = null, entryOverrides = {}) {
    const healthStats = health?.summary ? buildLoredeckStatsFromHealth(health) : null;
    const manifestStats = manifest?.stats && typeof manifest.stats === 'object' && !Array.isArray(manifest.stats) ? manifest.stats : {};
    const packStats = sourcePack?.stats && typeof sourcePack.stats === 'object' && !Array.isArray(sourcePack.stats) ? sourcePack.stats : {};
    const embeddedEntries = Object.values(entryOverrides || {});
    if (embeddedEntries.length) return buildLoredeckStatsFromEntries(embeddedEntries);
    return {
        entryCount: Number.isFinite(Number(packStats.entryCount))
            ? Number(packStats.entryCount)
            : Number.isFinite(Number(manifestStats.entryCount))
                ? Number(manifestStats.entryCount)
                : (healthStats?.entryCount || 0),
        categoryCounts: packStats.categoryCounts && typeof packStats.categoryCounts === 'object' && !Array.isArray(packStats.categoryCounts)
            ? { ...packStats.categoryCounts }
            : manifestStats.categoryCounts && typeof manifestStats.categoryCounts === 'object' && !Array.isArray(manifestStats.categoryCounts)
                ? { ...manifestStats.categoryCounts }
                : (healthStats?.categoryCounts || {}),
    };
}

function getLoredeckBundleSourceObject(sourcePack = {}, manifest = {}) {
    const source = sourcePack?.source && typeof sourcePack.source === 'object' && !Array.isArray(sourcePack.source) ? sourcePack.source : {};
    const update = manifest?.update && typeof manifest.update === 'object' && !Array.isArray(manifest.update) ? manifest.update : {};
    return {
        source,
        update,
    };
}

function getLoredeckUpdateUrl(pack = {}) {
    const source = pack?.source && typeof pack.source === 'object' && !Array.isArray(pack.source) ? pack.source : {};
    return String(source.updateUrl || pack.update?.url || source.url || '').trim();
}

function normalizeLoredeckUpdateFetchUrl(value = '') {
    const raw = String(value || '').trim();
    if (!raw) return '';
    try {
        const baseHref = typeof window !== 'undefined' ? window.location?.href : import.meta.url;
        const url = new URL(raw, baseHref || import.meta.url);
        if (/^https?:$/i.test(url.protocol) && url.hostname.toLowerCase() === 'github.com') {
            const parts = url.pathname.split('/').filter(Boolean);
            const blobIndex = parts.indexOf('blob');
            if (parts.length >= 5 && blobIndex === 2) {
                const [owner, repo] = parts;
                const branch = parts[3];
                const filePath = parts.slice(4).join('/');
                return `https://raw.githubusercontent.com/${owner}/${repo}/${branch}/${filePath}`;
            }
            const rawIndex = parts.indexOf('raw');
            if (parts.length >= 5 && rawIndex === 2) {
                const [owner, repo] = parts;
                const branch = parts[3];
                const filePath = parts.slice(4).join('/');
                return `https://raw.githubusercontent.com/${owner}/${repo}/${branch}/${filePath}`;
            }
        }
        return url.href;
    } catch (_) {
        return raw;
    }
}

async function fetchLoredeckUpdateBundle(updateUrl = '') {
    const url = normalizeLoredeckUpdateFetchUrl(updateUrl);
    if (!url) throw new Error('Loredeck has no update URL.');
    const response = await fetch(url, { cache: 'no-cache' });
    if (!response.ok) throw new Error(`Update fetch failed: HTTP ${response.status}`);
    try {
        return await response.json();
    } catch (e) {
        throw new Error(e?.message || 'Update URL did not return valid JSON.');
    }
}

function buildInstalledLoredeckRecordFromBundle(parsed = {}, options = {}) {
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
        throw new Error('Loredeck install file must be a JSON object.');
    }
    if (parsed.packs && typeof parsed.packs === 'object' && !parsed.pack && !parsed.manifest) {
        throw new Error('This is a Loredeck Library export. Use Import Library JSON instead.');
    }

    const now = Date.now();
    const bundleType = String(parsed.bundleType || (parsed.pack || parsed.manifest ? 'saga_loredeck_json' : '')).trim();
    const supportedBundleTypes = new Set(['saga_loredeck_json', 'saga_loredeck_library_record', 'saga_loredeck', '']);
    if (!supportedBundleTypes.has(bundleType)) {
        throw new Error(`Unsupported Loredeck bundle type: ${bundleType}.`);
    }
    const integrity = getLoredeckBundleIntegrity(parsed);
    const sourcePack = cloneLoredeckJson(parsed.pack || parsed.record || parsed.loredeck || (parsed.packId || parsed.id ? parsed : {})) || {};
    const manifest = cloneLoredeckJson(parsed.manifest || sourcePack.manifestData || parsed.manifestData || {}) || {};
    const health = parsed.health && typeof parsed.health === 'object' && !Array.isArray(parsed.health) ? parsed.health : null;
    const originalPackId = normalizeLoredeckPackId(sourcePack.packId || sourcePack.id || manifest.id || sanitizeFileStem(options.fileName || 'imported-loredeck'));
    if (!originalPackId) throw new Error('Loredeck bundle is missing a usable deck ID.');

    const originalType = String(sourcePack.type || manifest.type || 'custom').trim() || 'custom';
    const targetPackId = normalizeLoredeckPackId(options.targetPackId || '');
    const targetPack = targetPackId ? getLoredeckDefinition(targetPackId) : null;
    if (targetPackId && targetPack?.type === 'bundled') {
        throw new Error('Bundled Loredecks cannot be replaced by imported JSON.');
    }
    const existing = getLoredeckDefinition(originalPackId);
    const packId = targetPackId || (existing ? getUniqueLoredeckPackId(`${originalPackId}-custom`) : originalPackId);
    const title = String(sourcePack.title || manifest.title || packId).trim();
    const manifestRef = String(sourcePack.manifest || parsed.manifestRef || '').trim();
    const entryOverrides = normalizeImportedLoredeckEntryOverrideMap(
        parsed.entryOverrides || sourcePack.entryOverrides || {},
        [
            parsed.entries,
            manifest.entries,
            sourcePack.entries,
        ]
    );
    const disabledEntryIds = Array.isArray(parsed.disabledEntryIds)
        ? parsed.disabledEntryIds
        : (Array.isArray(sourcePack.disabledEntryIds) ? sourcePack.disabledEntryIds : []);
    if (!manifestRef && !Object.keys(entryOverrides).length) {
        throw new Error('Loredeck bundle has no fetchable manifest path and no embedded Lorecards to install.');
    }

    const { source, update } = getLoredeckBundleSourceObject(sourcePack, manifest);
    const updateUrl = String(source.updateUrl || update.url || targetPack?.source?.updateUrl || options.updateUrl || '').trim();
    const tags = parseLoredeckTags([
        ...(Array.isArray(sourcePack.tags) ? sourcePack.tags : []),
        ...(Array.isArray(manifest.tags) ? manifest.tags : []),
        'origin:imported',
        originalType === 'generated' ? 'origin:generated' : '',
    ].filter(Boolean).join(', '));
    const stats = getLoredeckBundleStats(sourcePack, manifest, health, entryOverrides);
    const record = {
        ...sourcePack,
        packId,
        type: 'custom',
        title,
        description: String(sourcePack.description || manifest.description || '').trim(),
        fandom: String(sourcePack.fandom || manifest.fandom || '').trim(),
        era: String(sourcePack.era || manifest.era || '').trim(),
        author: String(sourcePack.author || manifest.author || '').trim(),
        version: String(sourcePack.version || manifest.version || '1.0.0').trim(),
        entrySchemaVersion: Math.max(3, Number(sourcePack.entrySchemaVersion || manifest.entrySchemaVersion) || 0),
        manifest: manifestRef,
        source: {
            ...source,
            kind: 'imported_json',
            url: String(source.url || targetPack?.source?.url || '').trim(),
            updateUrl,
            installedFrom: String(options.fileName || targetPack?.source?.installedFrom || '').trim(),
            bundleType: bundleType || 'saga_loredeck_json',
            originalPackId,
            contentHash: integrity.computed,
            exportedAt: Number.isFinite(Number(parsed.exportedAt)) ? Number(parsed.exportedAt) : 0,
            importedAt: now,
        },
        tags,
        stats,
        healthStatus: String(health?.status || sourcePack.healthStatus || manifest.health?.status || '').trim(),
        derivedFrom: {
            ...(sourcePack.derivedFrom && typeof sourcePack.derivedFrom === 'object' && !Array.isArray(sourcePack.derivedFrom) ? sourcePack.derivedFrom : {}),
            kind: 'imported_loredeck',
            packId: originalPackId,
            title: String(sourcePack.title || manifest.title || originalPackId).trim(),
            type: originalType,
            version: String(sourcePack.version || manifest.version || '').trim(),
            sourceFile: String(options.fileName || '').trim(),
            importedAt: now,
        },
        entryOverrides,
        disabledEntryIds,
        timelineRegistry: normalizeLoredeckTimelineRegistry(parsed.timelineRegistry || sourcePack.timelineRegistry || manifest.timelineRegistry),
        tagRegistry: normalizeLoredeckTagRegistry(parsed.tagRegistry || sourcePack.tagRegistry || manifest.tagRegistry),
        pendingChanges: [],
        localModified: false,
        installedAt: targetPack?.installedAt || now,
        updatedAt: now,
    };

    const manifestSeed = {
        ...manifest,
        id: packId,
        type: 'custom',
        files: manifestRef ? manifest.files : [],
        stats,
    };
    record.manifestData = buildEmbeddedCustomManifest(manifestSeed, record);

    const warnings = [];
    if (!integrity.matches) warnings.push('Bundle content hash does not match the declared hash; review source before installing.');
    if (targetPackId) warnings.push(`Existing deck ${targetPackId} will be replaced with this imported bundle.`);
    else if (existing) warnings.push(`Deck ID ${originalPackId} already exists; installed as ${packId}.`);
    if (targetPack?.localModified) warnings.push(`${targetPackId} is marked locally modified; replacing it will overwrite local metadata and embedded Lorecards.`);
    if (originalType === 'generated') warnings.push('Generated bundle installed as editable Custom Loredeck.');
    const pendingCount = Array.isArray(parsed.pendingChanges) ? parsed.pendingChanges.length : (Array.isArray(sourcePack.pendingChanges) ? sourcePack.pendingChanges.length : 0);
    if (pendingCount) warnings.push(`${pendingCount} pending proposal${pendingCount === 1 ? '' : 's'} were not installed.`);
    if (!manifestRef) warnings.push('Installed from embedded JSON data without a fetchable source manifest.');

    return {
        record,
        warnings,
        originalPackId,
        originalType,
        bundleType: bundleType || 'saga_loredeck_json',
        contentHash: integrity.computed,
        declaredContentHash: integrity.declared,
        contentHashMatches: integrity.matches,
        embeddedEntryCount: Object.keys(entryOverrides).length,
        pendingDropCount: pendingCount,
        collision: !!existing,
    };
}

function getLoredeckInstallDuplicateMatches(install = {}) {
    const record = install.record || {};
    const originalPackId = String(install.originalPackId || record.source?.originalPackId || '').trim();
    const contentHash = String(record.source?.contentHash || '').trim();
    const titleKey = String(record.title || '').trim().toLowerCase();
    const versionKey = String(record.version || '').trim().toLowerCase();
    const fandomKey = String(record.fandom || '').trim().toLowerCase();
    const matches = [];
    const seen = new Set();

    for (const pack of getLoredeckLibrary(getState())) {
        if (!pack?.packId || seen.has(pack.packId)) continue;
        const source = pack.source && typeof pack.source === 'object' && !Array.isArray(pack.source) ? pack.source : {};
        const derivedFrom = pack.derivedFrom && typeof pack.derivedFrom === 'object' && !Array.isArray(pack.derivedFrom) ? pack.derivedFrom : {};
        const reasons = [];
        const exactHash = !!(contentHash && source.contentHash === contentHash);
        if (exactHash) reasons.push('same content hash');
        if (originalPackId && pack.packId === originalPackId) reasons.push('same deck ID');
        if (originalPackId && source.originalPackId === originalPackId) reasons.push('same source deck');
        if (originalPackId && derivedFrom.packId === originalPackId) reasons.push('same derived source');
        const sameTitleVersion = titleKey
            && titleKey === String(pack.title || '').trim().toLowerCase()
            && (!versionKey || versionKey === String(pack.version || '').trim().toLowerCase())
            && (!fandomKey || fandomKey === String(pack.fandom || '').trim().toLowerCase());
        if (!reasons.length && sameTitleVersion) reasons.push('same title/version');
        if (!reasons.length) continue;
        seen.add(pack.packId);
        matches.push({
            pack,
            reasons,
            exactHash,
            sameId: originalPackId && pack.packId === originalPackId,
            canReplace: pack.type !== 'bundled',
            localModified: pack.localModified === true,
        });
    }

    return matches.sort((a, b) => {
        if (a.exactHash !== b.exactHash) return a.exactHash ? -1 : 1;
        if (a.sameId !== b.sameId) return a.sameId ? -1 : 1;
        if (a.canReplace !== b.canReplace) return a.canReplace ? -1 : 1;
        return String(a.pack.title || a.pack.packId).localeCompare(String(b.pack.title || b.pack.packId));
    });
}

function analyzeLoredeckBundleInstall(parsed = {}, options = {}) {
    const install = buildInstalledLoredeckRecordFromBundle(parsed, options);
    const matches = getLoredeckInstallDuplicateMatches(install);
    const exactMatches = matches.filter(match => match.exactHash);
    if (exactMatches.length) {
        install.warnings.unshift(`${exactMatches.length} installed Loredeck${exactMatches.length === 1 ? '' : 's'} already match this bundle content hash.`);
    } else if (matches.length) {
        install.warnings.unshift(`${matches.length} possible duplicate Loredeck${matches.length === 1 ? '' : 's'} found.`);
    }
    return {
        ...install,
        matches,
    };
}

function cacheInstalledLoredeckBundle(installed = {}, parsed = {}) {
    if (installed.manifestData) {
        loredeckManifestPreviewCache.set(installed.packId, {
            manifest: installed.manifestData,
            health: parsed.health || null,
            error: '',
            loadedAt: Date.now(),
        });
    }
    if (canUseVirtualLoredeckData(installed)) {
        const entryCache = buildGeneratedLoredeckEntryCache(installed, installed.manifestData || {});
        loredeckEntryPreviewCache.set(installed.packId, {
            ...entryCache,
            health: parsed.health || null,
            error: '',
            loadedAt: Date.now(),
        });
    }
}

async function commitLoredeckBundleInstall(parsed = {}, record = {}, options = {}) {
    const result = upsertLoredeckLibraryPack(record);
    if (!result.ok) throw new Error(result.error || 'Loredeck install failed.');
    const installed = result.pack || record;
    cacheInstalledLoredeckBundle(installed, parsed);
    selectLoredeckForDetails(installed.packId, { refresh: false });
    options.overlay?.remove?.();
    refreshLoredeckSurfaces({ clearCanon: true, clearContext: true });
    const message = options.action === 'replace'
        ? `Updated Custom Loredeck: ${installed.title || installed.packId}.`
        : `Installed Custom Loredeck: ${installed.title || installed.packId}.`;
    toast(`${message}${options.warning ? ` ${options.warning}` : ''}`, options.warning ? 'warning' : 'success');
    return installed;
}

function createLoredeckInstallMatchRow(parsed = {}, install = {}, match = {}, overlay = null, fileName = '') {
    const row = document.createElement('div');
    row.className = 'wandlight-loredeck-install-match-row';
    if (match.exactHash) row.classList.add('wandlight-loredeck-install-match-exact');
    if (match.localModified) row.classList.add('wandlight-loredeck-install-match-modified');

    const main = document.createElement('div');
    main.className = 'wandlight-loredeck-install-match-main';
    const title = document.createElement('div');
    title.className = 'wandlight-loredeck-install-match-title';
    title.textContent = match.pack.title || match.pack.packId;
    main.appendChild(title);
    const meta = document.createElement('div');
    meta.className = 'wandlight-loredeck-install-match-meta';
    meta.textContent = [
        match.pack.packId,
        getLoredeckTypeLabel(match.pack.packId),
        match.reasons.join(', '),
        match.localModified ? 'locally modified' : '',
    ].filter(Boolean).join(' | ');
    main.appendChild(meta);
    row.appendChild(main);

    const actions = document.createElement('div');
    actions.className = 'wandlight-loredeck-install-match-actions';
    const replace = createButton(
        match.exactHash ? 'Reinstall' : 'Update',
        match.canReplace
            ? 'Replace this editable Loredeck record with the imported bundle.'
            : 'Bundled Loredecks cannot be replaced by imported JSON.',
        async (btn) => {
            if (!match.canReplace) return;
            if (match.localModified) {
                const ok = await confirmAction(
                    'Replace Locally Modified Loredeck',
                    `${match.pack.title || match.pack.packId} is marked locally modified. Replace it with the imported bundle anyway?`
                );
                if (!ok) return;
            }
            await runBusyAction(btn, 'Updating...', async () => {
                const updateInstall = buildInstalledLoredeckRecordFromBundle(parsed, {
                    fileName,
                    targetPackId: match.pack.packId,
                });
                await commitLoredeckBundleInstall(parsed, updateInstall.record, {
                    overlay,
                    action: 'replace',
                    warning: updateInstall.warnings[0] || '',
                });
            });
        },
        match.localModified ? 'wandlight-danger-button' : ''
    );
    replace.disabled = !match.canReplace;
    actions.appendChild(replace);
    row.appendChild(actions);
    return row;
}

function openLoredeckInstallPreviewDialog(parsed = {}, install = {}, options = {}) {
    document.querySelector('.wandlight-loredeck-install-overlay')?.remove();
    const updateMode = options.mode === 'update';
    const targetPack = options.targetPack || (options.targetPackId ? getLoredeckDefinition(options.targetPackId) : null);

    const overlay = document.createElement('div');
    overlay.className = 'wandlight-new-lore-overlay wandlight-loredeck-install-overlay';
    wireOverlayBackdropClose(overlay, () => overlay.remove());
    document.body.appendChild(overlay);

    const shell = document.createElement('div');
    shell.className = 'wandlight-new-lore-shell wandlight-loredeck-install-shell';
    overlay.appendChild(shell);

    const header = document.createElement('div');
    header.className = 'wandlight-lore-workbench-header';
    const titleWrap = document.createElement('div');
    titleWrap.className = 'wandlight-lore-workbench-title-wrap';
    const title = document.createElement('div');
    title.className = 'wandlight-lore-workbench-title';
    title.textContent = updateMode ? 'Loredeck Update Preview' : 'Install Loredeck JSON';
    titleWrap.appendChild(title);
    const subtitle = document.createElement('div');
    subtitle.className = 'wandlight-lore-workbench-subtitle';
    subtitle.textContent = updateMode
        ? 'Review fetched source data before updating this installed deck.'
        : 'Review source, duplicate matches, and install choice.';
    titleWrap.appendChild(subtitle);
    header.appendChild(titleWrap);
    header.appendChild(createButton('Close', 'Cancel this Loredeck install.', () => overlay.remove()));
    shell.appendChild(header);

    const form = document.createElement('div');
    form.className = 'wandlight-new-lore-form wandlight-loredeck-install-form';
    shell.appendChild(form);

    const record = install.record || {};
    const summary = document.createElement('div');
    summary.className = 'wandlight-loredeck-manifest-preview';
    const summaryTitle = document.createElement('div');
    summaryTitle.className = 'wandlight-runtime-card-title';
    summaryTitle.textContent = record.title || record.packId;
    summary.appendChild(summaryTitle);
    const chips = document.createElement('div');
    chips.className = 'wandlight-loredeck-entry-summary';
    chips.appendChild(createStatusPill(updateMode ? 'Update source' : 'Custom install', updateMode ? 'Fetched update data can replace this editable Loredeck after review.' : 'Imported bundles install as editable Custom Loredecks.'));
    chips.appendChild(createStatusPill(`${record.stats?.entryCount || 0} Lorecards`, 'Lorecards included or referenced by this bundle.'));
    chips.appendChild(createStatusPill(install.originalType || 'unknown source', 'Original bundle deck type.'));
    chips.appendChild(createStatusPill(install.bundleType || record.source?.bundleType || 'json bundle', 'Bundle format detected by the installer.'));
    if (install.contentHashMatches === false) chips.appendChild(createStatusPill('Hash mismatch', 'The declared bundle content hash does not match the computed content hash.'));
    if (record.healthStatus) chips.appendChild(createStatusPill(record.healthStatus, 'Deck Health status from the bundle.'));
    if (install.matches?.length) chips.appendChild(createStatusPill(`${install.matches.length} duplicate match${install.matches.length === 1 ? '' : 'es'}`, 'Installed decks that may overlap with this bundle.'));
    summary.appendChild(chips);

    const grid = document.createElement('div');
    grid.className = 'wandlight-loredeck-detail-grid';
    grid.appendChild(createKeyValue(updateMode ? 'Target ID' : 'Install ID', record.packId, updateMode ? 'Installed Loredeck that will be updated if accepted.' : 'Deck ID that will be used for a new-copy install.'));
    grid.appendChild(createKeyValue('Original ID', install.originalPackId || 'unset', 'Deck ID recorded in the imported bundle.'));
    grid.appendChild(createKeyValue('Fandom', record.fandom || 'unset', 'Fandom or setting metadata.'));
    grid.appendChild(createKeyValue('Version', record.version || 'unset', 'Imported deck version.'));
    grid.appendChild(createKeyValue('Bundle Type', install.bundleType || record.source?.bundleType || 'saga_loredeck_json', 'Supported Saga bundle format detected from this JSON.'));
    grid.appendChild(createKeyValue('Content Hash', record.source?.contentHash || 'unset', 'Deterministic hash of the imported JSON bundle used for duplicate checks.'));
    if (install.declaredContentHash && install.declaredContentHash !== record.source?.contentHash) {
        grid.appendChild(createKeyValue('Declared Hash', install.declaredContentHash, 'Hash declared inside the bundle before Saga recomputed the content fingerprint.'));
    }
    grid.appendChild(createKeyValue('Embedded Lorecards', String(install.embeddedEntryCount || 0), 'Lorecards embedded directly in this bundle and installable without fetching source files.'));
    grid.appendChild(createKeyValue('Pending Dropped', String(install.pendingDropCount || 0), 'Pending proposals are not installed; only accepted deck data is imported.'));
    grid.appendChild(createKeyValue('Update URL', record.source?.updateUrl || 'none', 'Creator-published update source if present.'));
    grid.appendChild(createKeyValue(updateMode ? 'Update Source' : 'File', options.updateUrl || options.fileName || record.source?.installedFrom || 'unknown', updateMode ? 'Fetched update URL.' : 'Selected local JSON file.'));
    summary.appendChild(grid);
    form.appendChild(summary);

    if (install.warnings?.length) {
        const warningList = document.createElement('div');
        warningList.className = 'wandlight-loredeck-generated-readiness-list';
        for (const warning of install.warnings) {
            const item = document.createElement('div');
            item.className = 'wandlight-loredeck-generated-readiness-item wandlight-loredeck-generated-readiness-warning';
            item.textContent = warning;
            warningList.appendChild(item);
        }
        form.appendChild(warningList);
    }

    const matches = document.createElement('div');
    matches.className = 'wandlight-loredeck-install-matches';
    const matchesTitle = document.createElement('div');
    matchesTitle.className = 'wandlight-runtime-card-title';
    matchesTitle.textContent = 'Duplicate Review';
    matches.appendChild(matchesTitle);
    if (!install.matches?.length) {
        matches.appendChild(createEmptyMessage('No installed Loredecks matched this bundle ID, source ID, title/version, or content hash.'));
    } else {
        const list = document.createElement('div');
        list.className = 'wandlight-loredeck-install-match-list';
        for (const match of install.matches) {
            list.appendChild(createLoredeckInstallMatchRow(parsed, install, match, overlay, options.fileName || ''));
        }
        matches.appendChild(list);
    }
    form.appendChild(matches);

    const actions = document.createElement('div');
    actions.className = 'wandlight-primary-actions';
    if (updateMode) {
        actions.appendChild(createButton('Update This Deck', 'Replace this editable Loredeck record with the fetched update bundle.', async (btn) => {
            if (targetPack?.localModified) {
                const ok = await confirmAction(
                    'Update Locally Modified Loredeck',
                    `${targetPack.title || targetPack.packId} is marked locally modified. Update it from the fetched source anyway?`
                );
                if (!ok) return;
            }
            await runBusyAction(btn, 'Updating...', async () => {
                await commitLoredeckBundleInstall(parsed, record, {
                    overlay,
                    action: 'replace',
                    warning: install.warnings?.[0] || '',
                });
            });
        }, targetPack?.localModified ? 'wandlight-danger-button' : 'wandlight-primary-button'));
    }
    actions.appendChild(createButton(updateMode ? 'Install As New Copy' : 'Install New Copy', 'Install this bundle as a separate Custom Loredeck record.', async (btn) => {
        await runBusyAction(btn, 'Installing...', async () => {
            const copyInstall = updateMode
                ? buildInstalledLoredeckRecordFromBundle(parsed, {
                    fileName: options.fileName || options.updateUrl || '',
                    updateUrl: options.updateUrl || '',
                })
                : install;
            await commitLoredeckBundleInstall(parsed, copyInstall.record, {
                overlay,
                action: 'install',
                warning: copyInstall.warnings?.[0] || '',
            });
        });
    }, updateMode ? '' : 'wandlight-primary-button'));
    actions.appendChild(createButton('Cancel', 'Cancel this Loredeck install.', () => overlay.remove()));
    form.appendChild(actions);
}

async function readLoredeckInstallFile(file) {
    const fileName = file?.name || 'selected-file.json';
    try {
        const text = await file.text();
        const parsed = JSON.parse(text);
        const install = analyzeLoredeckBundleInstall(parsed, { fileName });
        return { ok: true, fileName, parsed, install };
    } catch (e) {
        return { ok: false, fileName, error: e?.message || 'Loredeck JSON install failed.' };
    }
}

